84	// Run invokes a single agent harness and returns the result.
85	func (r *Runner) Run(opts RunOptions) (*Result, error) {
86		harness, harnessName, err := r.resolveHarness(opts)
87		if err != nil {
88			return nil, err
89		}
90	
91		// If the provider flag was consumed as a harness name (e.g. "agent",
92		// "local"), clear it so downstream code (RunAgent →
93		// resolveEmbeddedAgentProvider) doesn't try to look it up as a
94		// ddx-agent config provider name.
95		if opts.Provider != "" {
96			resolved := resolveHarnessAlias(opts.Provider)
97			if resolved == harnessName {
98				opts.Provider = ""
99			}
100		}
101	
102		// virtual harness: replay from dictionary instead of executing a binary.
103		if harnessName == "virtual" {
104			return runVirtualFn(r, opts)
105		}
106	
107		// Agent harness: run in-process via the embedded agent library.
108		if harnessName == "agent" {
109			return RunAgent(r, opts)
110		}
111	
112		// Script harness: execute directives against the real filesystem and git.
113		if harnessName == "script" {
114			return runScriptFn(r, opts)
115		}
116	
117		// HTTP-provider harnesses (lmstudio, openrouter, and any other harness
118		// registered with IsHTTPProvider=true and no Binary) have no CLI binary
119		// to exec. They MUST route through the embedded agent runtime, which
120		// speaks OpenAI-compatible APIs and can be pointed at any provider via
121		// --provider. Without this dispatch, the exec path below would call
122		// ExecuteInDir with harness.Binary="", producing a zero-duration
123		// "exec: no command" error (see ddx-501e87ef: cheap-tier attempts on
124		// lmstudio were burning <1s and escalating straight to smart tier).
125		if harness.IsHTTPProvider && harness.Binary == "" {
126			agentOpts := opts
127			// Surface the harness name as the provider so the embedded runtime
128			// knows which .agent/config.yaml provider block to use. If the caller
129			// already specified --provider, preserve their choice.
130			if agentOpts.Provider == "" {
131				agentOpts.Provider = harnessName
132			}
133			return RunAgent(r, agentOpts)
134		}
135	
136		prompt, err := r.resolvePrompt(opts)
137		if err != nil {
138			return nil, err
139		}
140	
141		model := r.resolveModel(opts, harnessName)
142	
143		// Warn on deprecated explicit model pin.
144		if model != "" {
145			cat := r.catalog()
146			if dp, deprecated := cat.CheckDeprecatedPin(model, harness.Surface); deprecated {
147				fmt.Fprintf(os.Stderr, "agent: model %q is deprecated; use %q instead\n", model, dp.ReplacedBy)
148			}
149		}
150	
151		// Warn on unknown model
152		if model != "" && len(harness.Models) > 0 && !containsString(harness.Models, model) {
153			fmt.Fprintf(os.Stderr, "agent: model %q is not a known model for harness %q; available models: %s\n",
154				model, harnessName, strings.Join(harness.Models, ", "))
155		}
156	
157		// Warn on unknown effort
158		if opts.Effort != "" {
159			levels := r.resolveReasoningLevels(harnessName, harness)
160			if len(levels) > 0 && !containsString(levels, opts.Effort) {
161				fmt.Fprintf(os.Stderr, "agent: effort %q is not a known reasoning level for harness %q; available levels: %s\n",
162					opts.Effort, harnessName, strings.Join(levels, ", "))
163			}
164		}
165	
166		timeout := r.resolveTimeout(opts)
167		wallClock := r.resolveWallClock(opts)
168	
169		// Build args with the resolved prompt (may have come from file)
170		resolvedOpts := opts
171		resolvedOpts.Prompt = prompt
172		resolvedOpts.Permissions = resolvePermissions(r.Config.Permissions, opts.Permissions)
173		args := BuildArgs(harness, resolvedOpts, model)
174		stdin := ""
175		if harness.PromptMode == "stdin" {
176			stdin = prompt
177		}
178	
179		// Execute
180		start := time.Now()
181		parentCtx := opts.Context
182		if parentCtx == nil {
183			parentCtx = context.Background()
184		}
185		ctx, cancel := context.WithCancel(parentCtx)
186		defer cancel()
187		ctx = withExecutionTimeout(ctx, timeout)
188		ctx = withExecutionWallClock(ctx, wallClock)
189	
190		// Use ExecuteInDir when WorkDir is set — this handles harnesses like
191		// claude that have no --cwd flag by setting cmd.Dir on the subprocess.
192		execDir := ""
193		if opts.WorkDir != "" && harness.WorkDirFlag == "" {
194			execDir = opts.WorkDir
195		}
196	
197		// Claude streaming path: when running against the real OSExecutor, pipe
198		// claude's stream-json stdout through parseClaudeStream so operators see
199		// real-time progress (tool calls, turn counts, elapsed) in
200		// `ddx server workers log` instead of a 20–40 minute silence. The path
201		// falls back to the legacy buffered --print behaviour automatically if
202		// the CLI rejects the stream-json flags.
203		if harnessName == "claude" {
204			if _, isOS := r.Executor.(*OSExecutor); isOS {
205				result, err := runClaudeWithFallbackFn(r, ctx, harness, harnessName, model, resolvedOpts, prompt, execDir, timeout)
206				if err == nil && result != nil {
207					finalizeClaudeResult(r, result, opts, prompt, time.Since(start))
208					return result, nil
209				}
210				// If the streaming path failed outright (not just claude exit != 0),
211				// fall through to the classic Executor path so behaviour degrades
212				// gracefully.
213			}
214		}
215	
216		execResult, execErr := r.Executor.ExecuteInDir(ctx, harness.Binary, args, stdin, execDir)
217		elapsed := time.Since(start)
218	
219		result := r.processResult(harnessName, model, harness, execResult, execErr, elapsed, ctx)
220		promptSource := opts.PromptSource
221		if promptSource == "" {
222			if opts.PromptFile != "" {
223				promptSource = opts.PromptFile
224			} else {
225				promptSource = "inline"
226			}
227		}
228		r.logSession(result, len(prompt), prompt, promptSource, opts.Correlation)
229		r.recordRoutingOutcome(result, elapsed, opts)
230		return result, nil
231	}
