233	// ValidateForExecuteLoop checks harness availability and model compatibility
234	// before any beads are claimed. Returns an error if the harness is not
235	// available or if the model is clearly incompatible with the harness
236	// (e.g. a local agent preset used with a non-agent harness). Emits a
237	// deprecation warning to stderr if the model pin is deprecated.
238	//
239	// Call this in execute-loop before starting the worker so failures are
240	// surfaced before any beads are claimed rather than mid-execution.
241	func (r *Runner) ValidateForExecuteLoop(harnessName, model, provider, modelRef string) error {
242		if harnessName == "" {
243			return nil // no explicit harness; routing will pick at claim time
244		}
245	
246		h, name, err := r.resolveHarness(RunOptions{Harness: harnessName})
247		if err != nil {
248			return err
249		}
250	
251		if model != "" {
252			cat := r.catalog()
253	
254			// Warn about deprecated model pins before any bead is claimed.
255			if dp, deprecated := cat.CheckDeprecatedPin(model, h.Surface); deprecated {
256				fmt.Fprintf(os.Stderr, "execute-loop: model %q is deprecated for harness %q; use %q instead\n",
257					model, name, dp.ReplacedBy)
258			}
259		}
260		return nil
261	}
