263	// Capabilities reports the model and reasoning options for a harness.
264	func (r *Runner) Capabilities(name string) (*HarnessCapabilities, error) {
265		harness, harnessName, err := r.resolveHarness(RunOptions{Harness: name})
266		if err != nil {
267			return nil, err
268		}
269	
270		caps := &HarnessCapabilities{
271			Harness:             harnessName,
272			Available:           true,
273			Binary:              harness.Binary,
274			ReasoningLevels:     r.resolveReasoningLevels(harnessName, harness),
275			Surface:             harness.Surface,
276			CostClass:           harness.CostClass,
277			IsLocal:             harness.IsLocal,
278			ExactPinSupport:     harness.ExactPinSupport,
279			SupportsEffort:      harness.EffortFlag != "",
280			SupportsPermissions: len(harness.PermissionArgs) > 0,
281		}
282		if path, err := r.LookPath(harness.Binary); err == nil {
283			caps.Path = path
284		}
285	
286		model := r.resolveModel(RunOptions{}, harnessName)
287		if model == "" {
288			model = harness.DefaultModel
289		}
290		if model != "" {
291			caps.Model = model
292			caps.Models = []string{model}
293		}
294	
295		// Build effective profile → model mappings for this harness from the catalog.
296		cat := r.catalog()
297		for _, profile := range []string{"cheap", "fast", "smart"} {
298			if m, ok := cat.Resolve(profile, harness.Surface); ok {
299				if caps.ProfileMappings == nil {
300					caps.ProfileMappings = make(map[string]string)
301				}
302				caps.ProfileMappings[profile] = m
303			}
304		}
305	
306		return caps, nil
307	}
