309	// resolveHarness looks up the harness by name and checks availability.
310	func (r *Runner) resolveHarness(opts RunOptions) (harnessConfig, string, error) {
311		name := opts.Harness
312		if name == "" {
313			// --provider names a harness directly (e.g. "agent", "local") →
314			// treat it as a harness override so the routing engine never
315			// falls through to a different harness.
316			if opts.Provider != "" {
317				resolved := resolveHarnessAlias(opts.Provider)
318				if r.registry.Has(resolved) {
319					name = resolved
320				}
321			}
322		}
323		if name == "" {
324			name = r.Config.Harness
325		}
326		harness, ok := r.registry.Get(name)
327		if !ok {
328			return harnessConfig{}, "", fmt.Errorf("agent: unknown harness: %s", name)
329		}
330		// Embedded and HTTP-only harnesses don't need a binary in PATH.
331		if name != "virtual" && name != "agent" && name != "script" && !harness.IsHTTPProvider {
332			if _, err := r.LookPath(harness.Binary); err != nil {
333				return harnessConfig{}, "", fmt.Errorf("agent: harness %s not available: %s not found in PATH", name, harness.Binary)
334			}
335		}
336		return harness, name, nil
337	}
