339	// resolvePrompt reads the prompt from text or file.
340	func (r *Runner) resolvePrompt(opts RunOptions) (string, error) {
341		prompt := opts.Prompt
342		if opts.PromptFile != "" {
343			data, err := readPromptFileBounded(opts.PromptFile)
344			if err != nil {
345				return "", fmt.Errorf("agent: read prompt file: %w", err)
346			}
347			prompt = string(data)
348		}
349		if prompt == "" {
350			return "", fmt.Errorf("agent: prompt is required")
351		}
352		return prompt, nil
353	}
