355	// resolveModel picks the model from opts, per-harness config, or global config.
356	func (r *Runner) resolveModel(opts RunOptions, harnessName string) string {
357		if opts.Model != "" {
358			return opts.Model
359		}
360		if m, ok := r.Config.Models[harnessName]; ok {
361			return m
362		}
363		if r.Config.Model != "" {
364			return r.Config.Model
365		}
366		return ""
367	}
