369	func (r *Runner) resolveReasoningLevels(harnessName string, harness harnessConfig) []string {
370		if r.Config.ReasoningLevels != nil {
371			if levels, ok := r.Config.ReasoningLevels[harnessName]; ok && len(levels) > 0 {
372				return append([]string{}, levels...)
373			}
374		}
375		if len(harness.ReasoningLevels) > 0 {
376			return append([]string{}, harness.ReasoningLevels...)
377		}
378		return []string{}
379	}
