381	// resolveTimeout picks the idle (inactivity) timeout from opts or config.
382	func (r *Runner) resolveTimeout(opts RunOptions) time.Duration {
383		if opts.Timeout > 0 {
384			return opts.Timeout
385		}
386		return time.Duration(r.Config.TimeoutMS) * time.Millisecond
387	}
