389	// resolveWallClock picks the absolute wall-clock cap from opts or config.
390	// This bound fires regardless of stream/event activity so a provider that
391	// emits heartbeats cannot pin the worker past the configured duration.
392	func (r *Runner) resolveWallClock(opts RunOptions) time.Duration {
393		if opts.WallClock > 0 {
394			return opts.WallClock
395		}
396		return time.Duration(r.Config.WallClockMS) * time.Millisecond
397	}
