410	// BuildArgs constructs the argument array for a harness invocation.
411	// Exported for testing.
412	func BuildArgs(h harnessConfig, opts RunOptions, model string) []string {
413		// Use BaseArgs if set, fall back to legacy Args for compatibility.
414		base := h.BaseArgs
415		if base == nil {
416			base = h.Args
417		}
418		args := append([]string{}, base...)
419	
420		// Append permission-specific args.
421		if h.PermissionArgs != nil {
422			level := opts.Permissions
423			if level == "" {
424				level = "safe"
425			}
426			if extra, ok := h.PermissionArgs[level]; ok {
427				args = append(args, extra...)
428			}
429		}
430	
431		if opts.WorkDir != "" && h.WorkDirFlag != "" {
432			args = append(args, h.WorkDirFlag, opts.WorkDir)
433		}
434		if model != "" && h.ModelFlag != "" {
435			args = append(args, h.ModelFlag, model)
436		}
437		if opts.Effort != "" && h.EffortFlag != "" {
438			if h.EffortFormat != "" {
439				args = append(args, h.EffortFlag, fmt.Sprintf(h.EffortFormat, opts.Effort))
440			} else {
441				args = append(args, h.EffortFlag, opts.Effort)
442			}
443		}
444		if h.PromptMode == "arg" {
445			args = append(args, opts.Prompt)
446		}
447		return args
448	}
