450	// processResult converts execution output to a Result.
451	func (r *Runner) processResult(harnessName, model string, harness harnessConfig, execResult *ExecResult, execErr error, elapsed time.Duration, ctx context.Context) *Result {
452		result := &Result{
453			Harness:    harnessName,
454			Model:      model,
455			DurationMS: int(elapsed.Milliseconds()),
456		}
457	
458		if execResult != nil {
459			result.Output = execResult.Stdout
460			result.Stderr = execResult.Stderr
461			result.ExitCode = execResult.ExitCode
462		}
463	
464		if execResult != nil && execResult.EarlyCancel {
465			result.Error = fmt.Sprintf("cancelled: auth/rate-limit detected (%s)", execResult.CancelReason)
466			result.ExitCode = -1
467		} else if execResult != nil && execResult.WallClockTimeout {
468			// Wall-clock cap fired regardless of stream activity; distinguish
469			// this from the resettable idle timer so operators can tell the two
470			// failure modes apart in result.json and session logs.
471			reportedElapsed := execResult.WallClockElapsed
472			if reportedElapsed == 0 {
473				reportedElapsed = elapsed
474			}
475			result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
476			result.ExitCode = -1
477		} else if execErr != nil {
478			if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
479				result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
480				result.ExitCode = -1
481			} else {
482				result.Error = execErr.Error()
483				if result.ExitCode == 0 {
484					result.ExitCode = -1
485				}
486			}
487		} else if execResult != nil && execResult.ExitCode != 0 {
488			result.Error = execResult.Stderr
489		}
490	
491		result.Tokens = ExtractTokens(result.Output, harness)
492		usage := ExtractUsage(harnessName, result.Output)
493		result.InputTokens = usage.InputTokens
494		result.OutputTokens = usage.OutputTokens
495		result.CostUSD = usage.CostUSD
496		return result
497	}
