499	// UsageData holds structured token usage from a structured agent output.
500	type UsageData struct {
501		InputTokens  int
502		OutputTokens int
503		CostUSD      float64
504	}
505	
506	// ExtractUsage parses structured token usage from agent output.
507	// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
508	// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
509	// Returns zero-value UsageData if parsing fails or the harness is unsupported.
510	func ExtractUsage(harnessName string, output string) UsageData {
511		switch harnessName {
512		case "codex":
513			for _, line := range strings.Split(output, "\n") {
514				line = strings.TrimSpace(line)
515				if line == "" || !strings.Contains(line, `"turn.completed"`) {
516					continue
517				}
518				var event struct {
519					Type  string `json:"type"`
520					Usage struct {
521						InputTokens  int `json:"input_tokens"`
522						OutputTokens int `json:"output_tokens"`
523					} `json:"usage"`
524				}
525				if err := json.Unmarshal([]byte(line), &event); err != nil {
526					continue
527				}
528				if event.Type == "turn.completed" {
529					return UsageData{
530						InputTokens:  event.Usage.InputTokens,
531						OutputTokens: event.Usage.OutputTokens,
532					}
533				}
534			}
535			return UsageData{}
536		case "claude":
537			// Claude may emit either the legacy single-JSON envelope
538			// ({"usage":{...},"total_cost_usd":N,"result":"..."}) or a stream-json
539			// sequence of one JSON event per line, the last of which is a
540			// {"type":"result",...} event with the same usage/cost fields.
541			return extractUsageClaude(output)
542		case "opencode":
543			// opencode -f json emits a JSON object; parse usage fields if present.
544			var envelope struct {
545				Usage struct {
546					InputTokens  int `json:"input_tokens"`
547					OutputTokens int `json:"output_tokens"`
548				} `json:"usage"`
549				TotalCostUSD float64 `json:"total_cost_usd"`
550			}
551			if err := json.Unmarshal([]byte(output), &envelope); err != nil {
552				// Try last non-empty line (in case of preamble).
553				lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
554				last := ""
555				for i := len(lines) - 1; i >= 0; i-- {
556					if strings.TrimSpace(lines[i]) != "" {
557						last = lines[i]
558						break
559					}
560				}
561				if last == "" {
562					return UsageData{}
563				}
564				if err2 := json.Unmarshal([]byte(last), &envelope); err2 != nil {
565					return UsageData{}
566				}
567			}
568			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
569				return UsageData{}
570			}
571			return UsageData{
572				InputTokens:  envelope.Usage.InputTokens,
573				OutputTokens: envelope.Usage.OutputTokens,
574				CostUSD:      envelope.TotalCostUSD,
575			}
576		case "pi":
577			// pi outputs JSONL - cost is in intermediate events, summary at end has no cost
578			// Scan backwards to find the last line with cost data
579			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
580			var inputTokens, outputTokens int
581			var costUSD float64
582			for i := len(lines) - 1; i >= 0; i-- {
583				line := strings.TrimSpace(lines[i])
584				if line == "" {
585					continue
586				}
587				// Try to parse as pi event with usage/cost
588				// Format: {"type":"text_end","message":{"usage":{"input":N,"output":M,"cost":{"total":X}}}}
589				var event struct {
590					Type    string `json:"type"`
591					Message struct {
592						Usage struct {
593							Input  int `json:"input"`
594							Output int `json:"output"`
595							Cost   struct {
596								Total float64 `json:"total"`
597							} `json:"cost"`
598						} `json:"usage"`
599					} `json:"message"`
600					Partial struct {
601						Usage struct {
602							Input  int `json:"input"`
603							Output int `json:"output"`
604							Cost   struct {
605								Total float64 `json:"total"`
606							} `json:"cost"`
607						} `json:"usage"`
608					} `json:"partial"`
609				}
610				if err := json.Unmarshal([]byte(line), &event); err != nil {
611					continue
612				}
613				// Check message.usage first, then partial.usage
614				if event.Message.Usage.Input > 0 || event.Message.Usage.Output > 0 {
615					inputTokens = event.Message.Usage.Input
616					outputTokens = event.Message.Usage.Output
617					costUSD = event.Message.Usage.Cost.Total
618					break
619				}
620				if event.Partial.Usage.Input > 0 || event.Partial.Usage.Output > 0 {
621					inputTokens = event.Partial.Usage.Input
622					outputTokens = event.Partial.Usage.Output
623					costUSD = event.Partial.Usage.Cost.Total
624					break
625				}
626			}
627			return UsageData{
628				InputTokens:  inputTokens,
629				OutputTokens: outputTokens,
630				CostUSD:      costUSD,
631			}
632		case "gemini":
633			// gemini outputs single JSON with stats.models[].tokens (no cost in JSON)
634			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
635			last := ""
636			for i := len(lines) - 1; i >= 0; i-- {
637				if strings.TrimSpace(lines[i]) != "" {
638					last = lines[i]
639					break
640				}
641			}
642			if last == "" {
643				return UsageData{}
644			}
645			var envelope struct {
646				Stats struct {
647					Models map[string]struct {
648						Tokens struct {
649							Input int `json:"input"`
650							Total int `json:"total"`
651						} `json:"tokens"`
652					} `json:"models"`
653				} `json:"stats"`
654			}
655			if err := json.Unmarshal([]byte(last), &envelope); err != nil {
656				return UsageData{}
657			}
658			inputTokens := 0
659			outputTokens := 0
660			for _, model := range envelope.Stats.Models {
661				inputTokens += model.Tokens.Input
662				outputTokens += model.Tokens.Total - model.Tokens.Input
663			}
664			// Gemini JSON output doesn't include cost
665			return UsageData{
666				InputTokens:  inputTokens,
667				OutputTokens: outputTokens,
668				CostUSD:      0,
669			}
670		default:
671			return UsageData{}
672		}
673	}
