675	// ExtractOutput extracts clean text from raw agent output based on harness format.
676	// For codex: scans JSONL for type=item.completed with item.type=agent_message, returns item.text
677	// For claude: parses JSON envelope and returns the 'result' field
678	// For agent/opencode: returns output as-is (no transformation needed)
679	// For unknown harnesses or malformed input: returns output as-is
680	func ExtractOutput(harnessName string, rawOutput string) string {
681		switch harnessName {
682		case "codex":
683			return extractOutputCodex(rawOutput)
684		case "claude":
685			return extractOutputClaude(rawOutput)
686		case "agent", "opencode":
687			// agent and opencode return clean text directly
688			return rawOutput
689		case "pi", "gemini":
690			return extractOutputPiGemini(rawOutput)
691		default:
692			// Unknown harnesses return output as-is
693			return rawOutput
694		}
695	}
