697	func extractOutputPiGemini(rawOutput string) string {
698		// pi outputs JSONL (last line has summary), gemini outputs single JSON
699		// Try to parse the last non-empty line for the response field
700		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
701		last := ""
702		for i := len(lines) - 1; i >= 0; i-- {
703			if strings.TrimSpace(lines[i]) != "" {
704				last = lines[i]
705				break
706			}
707		}
708		if last == "" {
709			return rawOutput
710		}
711		var envelope struct {
712			Response string `json:"response"`
713		}
714		if err := json.Unmarshal([]byte(last), &envelope); err != nil {
715			return rawOutput
716		}
717		return envelope.Response
718	}
