720	func extractOutputCodex(rawOutput string) string {
721		for _, line := range strings.Split(rawOutput, "\n") {
722			line = strings.TrimSpace(line)
723			if line == "" {
724				continue
725			}
726			var item struct {
727				Type string `json:"type"`
728				Item struct {
729					Type string `json:"type"`
730					Text string `json:"text"`
731				} `json:"item"`
732			}
733			if err := json.Unmarshal([]byte(line), &item); err != nil {
734				continue
735			}
736			if item.Type == "output" && item.Item.Type == "agent_message" {
737				return item.Item.Text
738			}
739		}
740		return rawOutput
741	}
