743	func extractOutputClaude(rawOutput string) string {
744		// Legacy non-streaming mode: single JSON envelope with a "result" field.
745		var envelope struct {
746			Result string `json:"result"`
747		}
748		if err := json.Unmarshal([]byte(rawOutput), &envelope); err == nil && envelope.Result != "" {
749			return envelope.Result
750		}
751		// Stream-json mode: scan lines for the final {"type":"result",...} event.
752		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
753		for i := len(lines) - 1; i >= 0; i-- {
754			line := strings.TrimSpace(lines[i])
755			if line == "" {
756				continue
757			}
758			var ev struct {
759				Type   string `json:"type"`
760				Result string `json:"result"`
761			}
762			if err := json.Unmarshal([]byte(line), &ev); err == nil {
763				if ev.Type == "result" && ev.Result != "" {
764					return ev.Result
765				}
766				if ev.Type == "" && ev.Result != "" {
767					// Legacy envelope as last line.
768					return ev.Result
769				}
770			}
771		}
772		return rawOutput
773	}
