775	// extractUsageClaude parses token usage and cost from claude output.
776	// It handles both the legacy non-streaming envelope and the stream-json
777	// format (one JSON event per line, final "result" event carries usage).
778	func extractUsageClaude(output string) UsageData {
779		parse := func(s string) (UsageData, bool) {
780			var envelope struct {
781				Type  string `json:"type"`
782				Usage struct {
783					InputTokens  int `json:"input_tokens"`
784					OutputTokens int `json:"output_tokens"`
785				} `json:"usage"`
786				TotalCostUSD float64 `json:"total_cost_usd"`
787			}
788			if err := json.Unmarshal([]byte(s), &envelope); err != nil {
789				return UsageData{}, false
790			}
791			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
792				return UsageData{}, false
793			}
794			return UsageData{
795				InputTokens:  envelope.Usage.InputTokens,
796				OutputTokens: envelope.Usage.OutputTokens,
797				CostUSD:      envelope.TotalCostUSD,
798			}, true
799		}
800	
801		// Try whole output as a single JSON envelope first (legacy path).
802		if u, ok := parse(output); ok {
803			return u
804		}
805		// Stream-json: scan lines, prefer the final "type":"result" event,
806		// else fall back to the last line that parses with usage.
807		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
808		for i := len(lines) - 1; i >= 0; i-- {
809			line := strings.TrimSpace(lines[i])
810			if line == "" {
811				continue
812			}
813			if u, ok := parse(line); ok {
814				return u
815			}
816		}
817		return UsageData{}
818	}
