820	// ExtractTokens parses token usage from agent output using the harness's pattern.
821	// For codex, it delegates to ExtractUsage and returns total tokens (input + output).
822	func ExtractTokens(output string, harness harnessConfig) int {
823		if harness.Name == "codex" {
824			usage := ExtractUsage("codex", output)
825			if usage.InputTokens > 0 || usage.OutputTokens > 0 {
826				return usage.InputTokens + usage.OutputTokens
827			}
828		}
829		if harness.TokenPattern == "" {
830			return 0
831		}
832		re, err := regexp.Compile(harness.TokenPattern)
833		if err != nil {
834			return 0
835		}
836		matches := re.FindStringSubmatch(output)
837		if len(matches) > 1 {
838			cleaned := strings.ReplaceAll(matches[1], ",", "")
839			n, _ := strconv.Atoi(cleaned)
840			return n
841		}
842		return 0
843	}
