913	// TestProviderConnectivity sends a lightweight probe to check if the provider is reachable and has credits.
914	// Returns ProviderStatus with connectivity information.
915	func (r *Runner) TestProviderConnectivity(harnessName string, timeout time.Duration) ProviderStatus {
916		status := ProviderStatus{Reachable: false}
917	
918		// Skip embedded harnesses - they don't have external providers
919		if harnessName == "virtual" || harnessName == "agent" {
920			status.Reachable = true
921			status.CreditsOK = true
922			return status
923		}
924	
925		harness, ok := r.registry.Get(harnessName)
926		if !ok {
927			status.Error = "unknown harness"
928			return status
929		}
930	
931		// Check if binary exists first
932		if harnessName != "virtual" && harnessName != "agent" {
933			if _, err := r.LookPath(harness.Binary); err != nil {
934				status.Error = "binary not found"
935				return status
936			}
937		}
938	
939		// Send a lightweight probe request to test connectivity
940		probePrompt := "echo ok"
941		opts := RunOptions{
942			Harness: harnessName,
943			Prompt:  probePrompt,
944			Timeout: timeout,
945		}
946	
947		start := time.Now()
948		result, err := r.Run(opts)
949		duration := time.Since(start)
950	
951		if err != nil {
952			status.Error = fmt.Sprintf("probe failed: %v (%.0fs)", err, duration.Seconds())
953			// Check for common error patterns indicating credit/quota issues
954			errStr := strings.ToLower(err.Error())
955			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
956				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
957				status.CreditsOK = false
958			}
959			return status
960		}
961	
962		// Check exit code and error from result
963		if result.ExitCode != 0 || result.Error != "" {
964			errStr := strings.ToLower(result.Error)
965			status.Error = fmt.Sprintf("probe failed: %s (%.0fs)", result.Error, duration.Seconds())
966			// Check for credit/quota errors
967			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
968				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
969				status.CreditsOK = false
970			}
971			return status
972		}
973	
974		// Probe succeeded
975		status.Reachable = true
976		status.CreditsOK = true
977		return status
978	}
