// AgentRunRuntime is the SD-024 successor to RunOptions for the agent
// run path. Durable knobs (Harness, Model, Provider, ModelRef, Effort,
// Permissions, Timeout, WallClock, SessionLogDir) are stripped — they
// live on config.ResolvedConfig and are passed via RunWithConfig's
// rcfg argument. Only non-serializable plumbing and per-invocation
// runtime intent remain.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 2 bead 17.
type AgentRunRuntime struct {
	Prompt                string
	PromptFile            string
	PromptSource          string
	Output                io.Writer
	Correlation           map[string]string
	Record                bool
	Replay                bool
	WorkDir               string
	EstimatedPromptTokens int
	RequiresTools         bool
	SessionLogDirOverride string
}

// QuorumOptions extends RunOptions for multi-agent consensus.

// RunWithConfig is the SD-024 successor to Run. It accepts a sealed
// ResolvedConfig (durable knobs) and an AgentRunRuntime (plumbing +
// per-invocation intent), assembles an equivalent RunOptions, and
// delegates to Run. Behavior is identical to Run with an
// equivalently-populated RunOptions.
//
// Stage 2 of SD-024: this method exists alongside Run; production
// callers have not migrated yet.
func (r *Runner) RunWithConfig(ctx context.Context, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}
	opts := RunOptions{
		Context:       ctx,
		Harness:       rcfg.Harness(),
		Prompt:        runtime.Prompt,
		PromptFile:    runtime.PromptFile,
		PromptSource:  runtime.PromptSource,
		Correlation:   runtime.Correlation,
		Model:         rcfg.Model(),
		Provider:      rcfg.Provider(),
		ModelRef:      rcfg.ModelRef(),
		Effort:        rcfg.Effort(),
		Timeout:       rcfg.Timeout(),
		WallClock:     rcfg.WallClock(),
		WorkDir:       runtime.WorkDir,
		Permissions:   rcfg.Permissions(),
		SessionLogDir: sessionLogDir,
	}
	return r.Run(opts)
}

// ValidateForExecuteLoop checks harness availability and model compatibility

// TestRunConfigOpts names every durable knob the agent run path reads
// via ResolvedConfig (per SD-024 §RunOptions → AgentRunRuntime field
// classification). Tests must specify each field explicitly; there are
// no zero-value defaults that silently bypass real config.
//
// See SD-024 / TD-024 §Test config constructors and §Stage 2 bead 17.
type TestRunConfigOpts struct {
	Harness       string
	Model         string
	Provider      string
	ModelRef      string
	Effort        string
	Permissions   string
	Timeout       time.Duration
	WallClock     time.Duration
	SessionLogDir string
}

// NewTestConfigForRun returns a *Config that, when Resolve()d with the
// matching CLIOverrides, produces a ResolvedConfig whose run-path
// accessors return the values supplied in opts. Pure CLI-override
// fields (Provider, ModelRef, Effort) have no durable home on
// AgentConfig and must be applied at Resolve time via CLIOverrides.
func NewTestConfigForRun(opts TestRunConfigOpts) *Config {
	return &Config{
		Version: "1.0",
		Agent: &AgentConfig{
			Harness:       opts.Harness,
			Model:         opts.Model,
			TimeoutMS:     int(opts.Timeout / time.Millisecond),
			SessionLogDir: opts.SessionLogDir,
			Permissions:   opts.Permissions,
		},
	}
}

